from . import ImagePalette

mode = im.im.getpalettemode()
im.palette = ImagePalette.ImagePalette(mode, im.im.getpalette(mode, mode))

if sort_palette:
    if not callable(sort_palette) and sort_palette not in (
        "brightness",
        "rgb",
    ):
        raise ValueError(
            "sort_palette must be 'brightness', 'rgb', or a callable"
        )

    used_palette_colors = [i for i, count in enumerate(im.histogram()) if count]
    palette_colors = im.im.getpalette("RGB")

    def sort_key(i):
        color = tuple(palette_colors[i * 3 : i * 3 + 3])
        if callable(sort_palette):
            return sort_palette(color)
        if sort_palette == "brightness":
            r, g, b = color
            return 0.299 * r + 0.587 * g + 0.114 * b
        return color

    used_palette_colors.sort(key=sort_key)
    im = im.remap_palette(used_palette_colors)

return im

